#include<bits/stdc++.h>
using namespace std;
long long f[100001], s[100001], n, m, aa, bb;
long long c[100001];
bool v[100001];
struct node {
	long long x;
	long long y;

};
struct cmp {
	bool operator()(node a, node b) {
		return a.y > b.y;
	}
};
vector<long long> a[100001][2];
priority_queue<node, vector<node>, cmp> q;
inline void di(int xx) {

	int x = xx;
	while (!q.empty()) {


		node now = q.top();
		q.pop();
		if (now.y != s[now.x]) continue;
        if (v[now.x]) continue;
		x = now.x;
		v[x] = 1;
		for (int i = 0; i < a[x][0].size(); i++) {

			if (s[a[x][0][i]] > s[x] + a[x][1][i]) {
				s[a[x][0][i]] = a[x][1][i] + s[x];
				f[a[x][0][i]] = x;
				node temp;

				q.push({a[x][0][i], s[a[x][0][i]]});
			}

		}
	}
}
int main() {
	std::ios::sync_with_stdio(false);
	std::cin.tie(nullptr);
	long long ans = 0;
	cin >> n >> m;
	cin >> aa >> bb;
	for (int i = 1; i <= n; i++) cin >> c[i];
	for (int i = 1; i <= n; i++) s[i] =  LLONG_MAX;
	for (int i = 1; i <= m; i++) {
		int x, y, z;
		cin >> x >> y >> z;
		a[x][0].push_back(y);
		a[x][1].push_back(z);
		a[y][0].push_back(x);
		a[y][1].push_back(z);

	}
	s[bb] = 0;
	q.push({bb, 0});
	di(bb);
	for (int i = 1; i <= n; i++) {
		if (s[i] < s[aa]) {
			ans += c[i];
		}
	}
	cout << ans;
	return 0;
}
